css:
/*作者：@kuku（小红书同名）  */

/*⚠️ 禁二传二改·禁商用倒卖*/




/* === 字体=== */
@font-face {
  font-family: "MiaoMiao";  
  src: url("https://files.catbox.moe/n3eac7.ttf") format("truetype");
  font-display: swap;       
}

body, button, input, textarea {
  font-family: "MiaoMiao", "Microsoft YaHei", sans-serif !important;
}




/*ui背景图🍉🍉*/
.drawer-content {
    background-image: url('https://files.catbox.moe/pysoky.jpeg');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}




/* 头像位置 */
div[is_user] .mesAvatarWrapper { 
    position: absolute;
    top: -17px !important; /* char头像上下位置🍉 */
    left: 29.2% !important;/* user和char头像的左右位置🍉 */
    transform: translateX(-50%);
    z-index: 9;
    margin: 0 !important;
}


div[is_user="true"] .mesAvatarWrapper {
    top: -17px !important; /* user头像的上下位置🍉 */
}


.avatar img {
    width: 40px !important;  
    height: 40px !important;
    min-width: unset !important;
    min-height: unset !important;
    box-shadow: none !important; 
    transition: all 0.3s ease; 
}

/* 头像尺寸调整 - 覆盖原有样式 */
.avatar img {
    width: 179px !important;  /* 宽🍉 */
    height: 147.5px !important; /* 高🍉 */
    object-fit: cover !important; 
    border-radius: 500% !important; 
    box-shadow: 0 4px 12px rgba(255,255,255,0.5) !important; 
}


.avatar img {
    filter: 
        sepia(0.7)    
        saturate(0.9) 
        brightness(0.95) 
        hue-rotate(-5deg); 
}

/* 调整对话框基础尺寸 */
.mes {
    --bubble-width: 93%;  
    --vertical-spacing: 4rem; 

    width: var(--bubble-width) !important;
    min-height: var(--bubble-min-height);
    margin: var(--vertical-spacing) auto !important; 
    padding: 1rem 0.8rem !important; 
}

/* 框长度 */
.mes_text {
    padding: 140px 1px 80px 1px !important; /* 上 右 下 左 */
}

.mes_block {
    position: relative;
    z-index: 999 !important; 
    isolation: isolate; 
}

#chat .ch_name {
    position: relative;
    padding-top: calc(var(--mainFontSize) * 1.2) !important; /* 增加顶部内边距 */
    margin-top: 0.8em !important; /* 增加顶部外边距 */
    transform: translateY(140px); /* 新增位移 */
}


/* 聊天气泡 */
.mes {
    background: linear-gradient(
        to bottom, 
        rgba(245,238,228,1) 60%, 
        rgba(245,238,228,1) 100%
    ) !important; 
    border: 2px solid #030305 !important;
    box-shadow: 
        0 0 0 1.4px #F6EFE5, 
        0 5px 2px rgba(0, 0, 0, 0.5) !important; 
    backdrop-filter: blur(16px); 
    left: 2px;
}

#chat {
  background-color: var(--chat-background-color) !important;
  backdrop-filter: none !important; 
}

/* 上半部分 */
.mes::before {
    content: "";
    position: absolute;
    top: -85px; /* 上下🍓 */
    left: 50%;/* 左右🍓 */
    transform: translateX(-50%);
    width: 333px;/* 尺寸大小🍓 */
    height: 300px;/* 尺寸大小🍓 */
    background: url(https://files.catbox.moe/bsqoq7.png) no-repeat center/contain;
    z-index: 1; 
}

/* 下半部分 */
.mes::after {
    content: "";
    position: absolute;
    bottom: -20px; /* 上下🍓 */
    right: -3.6px; /* 左右🍓 */
    width: 333px;/* 尺寸大小🍓 */
    height:333px; /* 尺寸大小🍓 */
    background-image: url("https://files.catbox.moe/ihi1rr.png");
    background-size: contain;
    background-repeat: no-repeat;
    background-position: right bottom;
    mix-blend-mode: normal; 
    z-index: 3; 
}



/* 消息ID */
.mesIDDisplay {
    position: absolute !important;
    top: 203px !important;
    left: 100px !important;
    display: inline-block !important;
    font-size: 0.7em !important;
    font-family: "MiaoMiao";
    z-index: 888 !important;
    opacity: 0.6;
}

/* 时间戳 */
.mes_timer {
    position: absolute !important;
    top: 203px !important;
    left: 165px !important;  
    font-size: 0.7em !important;
    color: var(--text-color-sec) !important;
    display: flex !important;
    gap: 4px;
    z-index: 888 !important;
    opacity: 0.6;
}

/* 词符数 */
.tokenCounterDisplay {
    position: absolute !important;
    top: 203px !important;
    left: 125px !important;  
    display: flex !important;
    font-size: 0.7em !important;
    z-index: 888 !important;
    opacity: 0.6;
}

#completion_prompt_manager .completion_prompt_manager_footer {
    padding: 0;
}
#completion_prompt_manager #completion_prompt_manager_list {
    padding: 10px 15px 15px 15px;
    margin: 5px 0;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: var(--SmartThemeBodyColor);
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action:hover {
    filter: brightness(1.2);
    text-decoration: none;
}

#prompt-manager-reset-character, #completion_prompt_manager_popup .completion_prompt_manager_popup_entry_form_footer #completion_prompt_manager_popup_entry_form_reset {
    color: var(--customThemeColor-purple);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span,
#completion_prompt_manager .completion_prompt_manager_header_advanced span {
    filter: drop-shadow(0px 0px 2px var(--SmartThemeChatTintColor));
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
    border: 1px solid 1px solid var(--SmartThemeBorderColor);
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: var(--customThemeColor-purple);
}

input[type="text"],
input[type="number"],
textarea:not([type="search"]):focus {

}

.text_pole:not(.objective-task) {
  background-color: var(--ui-color-sec);
  border: none;
}

blockquote,
.quote-style,
[class*="quote"] {
    background-color: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 0 !important;
    margin: 0.8em 0 !important;
}

blockquote::before,
blockquote::after {
    content: "" !important;
}


/* 添加在全局样式中 */
#top-bar {

   z-index: 1000; 
}

#top-bar::after {
    content: "";
    position: fixed;
    top: var(--topBar-height, 0px); 
    left: 0;
    width: 100%;
    height: 105px;
    background: url('https://files.catbox.moe/mpf2px.png') center/cover no-repeat;
    z-index: 999; 
    pointer-events: none; 
    filter: opacity(0.) drop-shadow(0 2px 4px rgba(0,0,0,0.0));
}

#main-content {
    margin-top: 150px; 
}

/* 滑块图案 */
input[type="range"]::-webkit-slider-thumb {
    width: 55px;
    height: 55px; 
    background: url('https://files.catbox.moe/lvu7b8.png') no-repeat center center; 
    background-size: contain; 
    border: none;
    border-radius: 0; 
    box-shadow: none;
    transition: width 0.2s, height 0.2s;
    z-index: 2;
}



/* 层级覆盖保障 */
.avatar,
.avatar::before,
.avatar::after {
    z-index: auto !important; /* 重置头像层级 */
}

q {
  text-decoration: underline dotted rgba(98, 137, 73, 0.6);
  text-underline-offset: 3px;
  font-style: normal;
}



/* 代码块 */
code, .hljs {
  position: relative;
  background: linear-gradient(
    20deg,
    rgba(218,215,198,0.3) 10%,
    rgba(218,215,198,0.4) 80%
  ) !important;
  border-radius: 4px !important;
  box-shadow: 
    2px 2px 4px rgba(0,0,0,0.02), 
    inset -2px -2px 6px rgba(0,0,0,0.1), 
    inset 2px 2px 4px rgba(255,255,255,0.); 
  border: 1px solid rgba(200,200,255,0.) !important;
  transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
   color: #9D8573;
}

/* ===== 外部装饰图标 ===== */
pre {
  position: relative; 
  margin-bottom: 2em !important; 
  overflow: visible !important; 
}

pre::after {
  content: "";
  position: absolute;
  bottom: -4px;  
  right: -5px;
  width: 30px;    
  height: 30px;
  background-image: url("https://files.catbox.moe/p5yy7o.png");
  background-size: contain;

  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1; 
}


/* 果冻风格下拉框 */
select {
    --jelly-color: #FBF3DE;   /* 主色 */
    --shadow-color: #FBF3DE; /* 投射色 */
    background: 
        linear-gradient(145deg, 
            rgba(251,243,222,1) 10%, 
            rgba(255,255,255,0.0) 90%) !important;
    border: px solid rgba(45,45,45,0.14) !important;
    border-radius: 5px !important;
    box-shadow:
        0 2px 5px -4px rgba(157,134,91,4),
        inset 0 4px 4px rgba(255,255,255,0),
        inset 0 -2px 4px rgba(255,255,255,0) !important;
    transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.1) !important;
    padding: px 36px 12px 16px !important;
    color: #454545 !important;
    backdrop-filter: blur(8px);
    position: relative;
}

/* 果冻材质层 */
select::after {
    content: "";
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    border-radius: 10px;
    background: 
        linear-gradient(135deg, 
            rgba(255,255,255,0) 0%, 
            rgba(239,204,218,0) 100%);
    mix-blend-mode: overlay;
    pointer-events: none;
}




/* 聚焦状态微调 */
input[type="text"]:focus,
input[type="number"]:focus,
input[type="switch"]:focus,
input:not([type]):focus,
textarea:not([type="search"]):focus {
    border-color: #EFCCDA !important; /* 加深边框色 */
    box-shadow: 0 0 0 2px rgba(141, 222, 225, 0.3) !important;
}






/* 自定义勾选框配色 */
input[type="checkbox"] {
    --checkbox-bg: #F4E2CC;  /* 基础背景色 */
    --checkbox-accent: #E4DBC4; /* 强调色 */

    background-color: var(--checkbox-bg) !important;
    box-shadow: 0 0 0 px var(--checkbox-accent) !important;
    transition: all 0.2s ease;
}

/* 选中状态 */
input[type="checkbox"]:checked {
    background-color: var(--checkbox-accent) !important;
    box-shadow: 0 0 0 0px var(--checkbox-bg) !important;
}

/* 对勾符号 */
input[type="checkbox"]::before {
    box-shadow: inset 1em 1em var(--checkbox-bg) !important;
    filter: contrast(0.1);
}

/* 爱心图标 */
input[type="checkbox"]:checked::after {
    content: "";
    position: absolute;
    left: 50%;
    top: 50%;
    transform: translate(-50%, -50%);
    font-size: 12px;
    line-height: 1;
    color: #454545;
    text-shadow: 0 2px 4px rgba(255,107,107,0.2);
}


/* EFCCDA+454545 */
:root {
  --jelly-bg: #F4E2C;         /* 果冻基底色 */
  --jelly-accent: #DEC4A5;     /* 立体投射色 */
  --jelly-shadow: rgba(69, 69, 69, 0.);
  --jelly-highlight: rgba(255, 255, 255, 0.2);
}

/* 立体核心样式 */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  background: linear-gradient(
    145deg,
    var(--jelly-bg) 30%,
    color-mix(in srgb, var(--jelly-bg) 90%, white 10%)
  ) !important;
  border: px solid var(--jelly-accent) !important;
  box-shadow: 
    0 4px 18px var(--jelly-shadow),
    inset 2px 2px 4px var(--jelly-highlight),
    inset -2px -2px 4px color-mix(in srgb, var(--jelly-accent) 20%, transparent) !important;
  border-radius: 5px;
  backdrop-filter: blur(4px);
  transition: all 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
  position: relative;
  overflow: hidden;
}



/* 立体文字样式 */
.standoutHeader strong,
.inline-drawer-header h4 {
  color: var(--jelly-accent) !important;
  text-shadow: 
    1px 1px 0 color-mix(in srgb, white 60%, var(--jelly-bg)),
    -1px -1px 1px var(--jelly-shadow);
  font-weight: 700;
  letter-spacing: 0.8px;
  position: relative;
  z-index: 2;
}




/* 极简渐变滚动条 */
::-webkit-scrollbar {
    width: 4px !important; 
    height: 5px !important; 
}

::-webkit-scrollbar-track {
    background: transparent !important; 
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(to bottom, 
        #F4E2CC 0%, 
        #F4E2CC 5%, 
        #DEC4A5 51%, 
        #F4E2CC 100%) !important;
    border-radius: 2px !important;
    border: none !important;
    transition: all 0.3s ease !important;
}






/* 输入框 */
input[type="text"],
input[type="number"],
input[type="switch"],
input:not([type]),
textarea:not([type="search"]) {
    background-color: #FFF9F1 !important; 


}




/* 角色管理头像 */
#right-nav-panel .character_select .avatar {
    --avatar-base-size: 50px !important; 
    width: var(--avatar-base-size) !important;
    height: var(--avatar-base-size) !important;
    transform: scale(1) !important; 
    margin: 5px auto !important; 

}


#right-nav-panel .character_select .avatar img {
    width: 100% !important;
    height: 100% !important;
    border-radius: 5px !important;
    object-fit: cover;
}




/* 移除特定界面头像装饰 */
#character_popup .avatar::before, 
#character_popup .avatar::after,
#user-settings-block .avatar::before, 
#user-settings-block .avatar::after,
#right-nav-panel .avatar::before, 
#right-nav-panel .avatar::after {
    display: none !important;
    background-image: none !important;
    animation: none !important;
}

/* 恢复原始头像样式 */
#character_popup .avatar img,
#user-settings-block .avatar img,
#right-nav-panel .avatar img {
    clip-path: none !important;
    border-radius: var(--box-border-radius) !important;
    position: static !important;
    filter: none !important;
}

/* 用户界面 */
#persona-management-button .avatar img {
    width: 52px !important;
    height: 52px !important;
    object-fit: cover;
    transition: all 0.3s ease;
    border-radius: 5px !important;
}




/* neo-range-input 背景美化 */
.neo-range-input {
    position: relative;
    background: linear-gradient(
            to right,
            rgba(255,240,219,0.2) 0%,
            rgba(255,240,219,0.2) 100%
        ),

    background-blend-mode: soft-light, multiply;
    box-shadow: inset 0 2px 8px rgba(0,0,0,0.2) !important;
}




/* 去除阴影 */
.mes_button,
.mes_edit_buttons,
#completion_prompt_manager
  #completion_prompt_manager_list
  li.completion_prompt_manager_prompt
  span
  span
  span {
  filter: none !important;
}

input:disabled, 
select:disabled, 
textarea:disabled {
  background: rgba(237, 229, 216, 0.6) !important;
  color: #9E7C6E !important;
  border-style: dashed !important;
}

.drawer-icon::before,
#leftNavDrawerIcon::before,
#rightNavDrawerIcon::before {
    content: '';
    display: block;
    width: 40px;
    height: 40px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    margin-right: px;
    margin-left: -8px;
}
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 12px;
}

/* 调整图标容器样式 */
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 1px;
}

/* 强制非悬停 */
.drawer-icon,
.fa-bars,
#extensionsMenuButton,
.fa-paper-plane {
  opacity: 1 !important;
  transition: opacity 0.2s ease !important;
}

/* 左侧导航图标 */
#leftNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/9o9zqa.png');
}

/* 系统设置图标 */
#sys-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/qnoxqy.png');
}

/* 高级格式图标 */
#advanced-formatting-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/b273n8.png');
}

/* 世界信息图标 */
#WI-SP-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/6erjuf.png');
}

/* 用户设置图标 */
#user-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/nemcbq.png');
}

/* Logo图标 */
#logo_block .drawer-icon::before {
    background-image: url('https://files.catbox.moe/fcmznd.png');
}

/* 扩展设置图标 */
#extensions-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/4ahxrm.png');
}

/* 记忆表格 */
#table_drawer_icon::before {
    background-image: url('https://files.catbox.moe/66ok78.png');
}

/* 角色管理图标 */
#persona-management-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/bslmqi.png');
}



/* 右侧导航图标 */
#rightNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/mtvf0g.png');
}





/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/345as5.png') center/contain no-repeat !important;
  width: 38px !important;
  height: 35px !important;

}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/lvu7b8.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-top: 1px !important;
}

/* 发送按钮 */
.fa-paper-plane {
  background: url('https://files.catbox.moe/sa5ztn.png') center/contain no-repeat !important;
  width: 30px !important;
  height: 30px !important;
  margin-left: 1px !important;

}


/* Font Awesome类图标 */
.fa-bars::before,           
.fa-ellipsis-v::before,     
.fa-paper-plane::before,     
#extensionsMenuButton::before {  
  display: none !important;
  content: '' !important;  
}


   body.no-blur #top-bar {
    box-shadow: none;
  }

#send_form:hover #qr--bar {    height: 40px;    transition: all 0.5s ease;}#qr--bar {    height: 0.1px;}
